import os
import subprocess
import sys

def create_backup(source_dir, output_format):
    if not os.path.isdir(source_dir):
        print(f"Error: Source directory '{source_dir}' does not exist.")
        sys.exit(1)

    base_name = os.path.basename(os.path.abspath(source_dir))
    parent_dir = os.path.dirname(os.path.abspath(source_dir))
    
    if not parent_dir: # if source_dir is a root directory like /home
        parent_dir = "/"

    if output_format == "tar.gz":
        output_filename = f"{base_name}.tar.gz"
        cmd = ["tar", "-czf", output_filename, "-C", parent_dir, base_name]
    elif output_format == "tar.bz2":
        output_filename = f"{base_name}.tar.bz2"
        cmd = ["tar", "-cjf", output_filename, "-C", parent_dir, base_name]
    elif output_format == "zip":
        output_filename = f"{base_name}.zip"
        # zip needs to be run from the parent directory of the source_dir
        # so that the archive doesn't contain the full path /home/user/dir
        cmd = ["zip", "-r", output_filename, base_name]
        os.chdir(parent_dir) # Change current directory for zip
    elif output_format == "7z":
        output_filename = f"{base_name}.7z"
        # 7z also benefits from running from the parent directory for cleaner archives
        cmd = ["7z", "a", "-r", output_filename, base_name]
        os.chdir(parent_dir) # Change current directory for 7z
    else:
        print(f"Error: Unsupported format '{output_format}'. Supported formats are: tar.gz, tar.bz2, zip, 7z.")
        sys.exit(1)

    print(f"Creating backup of '{source_dir}' to '{output_filename}'...")

    try:
        # Popen is used for compatibility across Python versions and better error handling
        process = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        stdout, stderr = process.communicate()

        if process.returncode == 0:
            print(f"Backup created successfully: {os.path.join(os.getcwd(), output_filename)}")
        else:
            print(f"Error creating backup: {stderr.decode().strip()}")
            sys.exit(1)
    except FileNotFoundError:
        print(f"Error: The command for '{output_format}' (e.g., tar, zip, 7z) was not found.")
        print("Please ensure the necessary compression utility is installed and available in the system PATH.")
        sys.exit(1)
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        sys.exit(1)

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <format>")
        print("Formats: tar.gz, tar.bz2, zip, 7z")
        sys.exit(1)

    source_directory = sys.argv[1]
    backup_format = sys.argv[2]
    
    # Store original working directory to revert later if needed (especially for zip/7z)
    original_cwd = os.getcwd()

    try:
        create_backup(source_directory, backup_format)
    finally:
        # Always revert to the original working directory
        os.chdir(original_cwd)